#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long p,l,h;
    bool operator<(const node&b)const
    {
        return p<b.p;
    }
}a[10010];
long long x[10010],y[10010],dp[2][10010],n,m,k,cnt=1;
int main()
{
    scanf("%lld%lld%lld",&n,&m,&k);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld",&x[i],&y[i]);
    }
    for(long long i=1;i<=k;i++)
    {
        scanf("%lld%lld%lld",&a[i].p,&a[i].l,&a[i].h);
    }
    sort(a+1,a+1+k);
    for(long long i=1;i<=n;i++)
    {
        long long now=(i&1),pre=((i&1)^1);
        for(long long j=0;j<=m;j++)
        {
            dp[now][j]=2e18;
        }
        for(long long j=x[i]+1;j<=m+x[i];j++)
        {
            dp[now][j]=min(dp[pre][j-x[i]],dp[now][j-x[i]])+1;
        }
        for(long long j=m+1;j<=m+x[i];j++)
        {
            dp[now][m]=min(dp[now][m],dp[now][j]);
        }
        for(long long j=1;j<=m-y[i];j++)
        {
            dp[now][j]=min(dp[now][j],dp[pre][j+y[i]]);
        }
        if(a[cnt].p==i)
        {
            for(long long j=0;j<=a[cnt].l;j++)
            {
                dp[now][j]=2e18;
            }
            for(long long j=a[cnt].h;j<=m;j++)
            {
                dp[now][j]=2e18;
            }
            int flag=0;
            for(long long j=1;j<=m;j++)
            {
                if(dp[now][j]<1e18)
                {
                    flag=1;
                    break;
                }
            }
            if(flag==0)
            {
                printf("0\n%lld",cnt-1);
                return 0;
            }
            cnt++;
        }
    }
    long long ans=LLONG_MAX;
    for(long long i=1;i<=m;i++)
    {
        ans=min(ans,dp[n&1][i]);
    }
    printf("1\n%lld",ans);
    return 0;
}
